import React from 'react';
import { FormControl, InputLabel, MenuItem, Select } from '@material-ui/core';
import useStyles from './styles';

function CategorySelect({
  selectedCategory,
  showExistingCategories,
  handleSelectChange,
  menuData,
  handleSubCategoryChange,
  selectedSubCategoryValues,
  existingCategories,
}) {
  const classes = useStyles();

  return (
    <FormControl variant="outlined" className={classes.formControl}>
      <InputLabel id="category-label">Category</InputLabel>
      <Select
        labelId="category-label"
        id="category-select"
        value={selectedCategory}
        onChange={handleSelectChange}
        label="Category"
      >
        {menuData.categories.map((category) => (
          <MenuItem key={category.mainMenu} value={category.mainMenu}>
            {category.mainMenu}
          </MenuItem>
        ))}
      </Select>
      <InputLabel id="subcategory-label">Subcategory</InputLabel>
      <Select
        labelId="subcategory-label"
        id="subcategory-select"
        multiple
        value={selectedSubCategoryValues}
        onChange={handleSubCategoryChange}
        label="Subcategory"
      >
        {showExistingCategories &&
          existingCategories.map((category) => (
            <MenuItem key={`${category.main}-${category.sub}`} value={`${category.main}-${category.sub}`}>
              {category.sub}
            </MenuItem>
          ))}
        {selectedCategory &&
          menuData.subCategories[selectedCategory] &&
          menuData.subCategories[selectedCategory].map((subcategory) => (
            <MenuItem key={subcategory} value={subcategory}>
              {subcategory}
            </MenuItem>
          ))}
      </Select>
    </FormControl>
  );
}

export default CategorySelect;
